function age(b){if(!b)return null;const t=new Date(),bd=new Date(b+"T00:00:00");let a=t.getFullYear()-bd.getFullYear();if(t.getMonth()<bd.getMonth()||(t.getMonth()===bd.getMonth()&&t.getDate()<bd.getDate()))a--;return a}
function M({open,onClose,title,children,wide}){if(!open)return null;return(<div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-40" onClick={onClose}><div className={"bg-white rounded-2xl shadow-2xl mx-4 max-h-[85vh] overflow-y-auto "+(wide?"max-w-2xl w-full":"max-w-lg w-full")} onClick={e=>e.stopPropagation()}><div className="flex items-center justify-between px-6 py-4 border-b"><h2 className="text-lg font-bold">{title}</h2><button onClick={onClose} className="p-1 rounded-lg hover:bg-gray-100"><X size={20}/></button></div><div className="px-6 py-4">{children}</div></div></div>)}
